windowclass.script:
local _nRolls = 0;
function onInit()
	if super and super.onInit() then
		super.onInit();
	end
	self.resetNumRolls();
	OptionsManager.registerCallback("CL07", self.refresh);
	self.refresh();
end
function onClose()
	OptionsManager.unregisterCallback("CL07", self.refresh);
end
function getNumRolls()
	return _nRolls;
end
function resetNumRolls()
	_nRolls = 0;
end
function decreaseNumRolls()
	_nRolls = _nRolls - 1;
end
function increaseNumRolls()
	_nRolls = _nRolls + 1;
end
function refresh()
	local bShow = (string.lower(OptionsManager.getOption("CL07")) == string.lower(Interface.getString("option_val_threecolumn")));
	label_extra_roll_1.setVisible(bShow);
	label_extra_roll_2.setVisible(bShow);
	button_shiftTempLeft.setVisible(bShow);
	button_shiftTempRight.setVisible(bShow);
	button_shiftPotLeft.setVisible(bShow);
	button_shiftPotRight.setVisible(bShow);
	button_shiftExtraLeft.setVisible(bShow);
	button_shiftExtraRight.setVisible(bShow);
end

combobox_labeled_RMC.script:
function onInit()
	super.onInit();
	addItems(Rules_Professions.List());
end
function onValueChanged()
	local professionRealm = Rules_Professions.Realm(getValue());
	if professionRealm ~= "Pick One" then
		DB.setValue(window.getDatabaseNode(), "realm", "string", professionRealm);
	end
	for i, win in ipairs(window.abilities.getWindows()) do
		win.refresh();
	end
end

button_text.script:
function onButtonPress()
	numRolls = window.getNumRolls();
	if numRolls > 0 then
		statmsg = "Stat Generation: " .. window.name.getValue() .. " can't apply new stats until all rolls have completed.";
		msgicon = "indicator_stop";
	else
		readyToApply = true;
		for i, win in ipairs(window.abilities.getWindows()) do
			if win.temp.getValue() < 1 or win.pot.getValue() < 1 then
				readyToApply = false;
			end
		end
		if not readyToApply then
			statmsg = window.name.getValue() .. "\r"
			statmsg = statmsg .. "Stat Generation: Can't apply new stats until all stats have a value.\r";
			msgicon = "indicator_stop";
		else							
			statmsg = window.name.getValue() .. "\r"
			statmsg = statmsg .. "Stat Generation: \r";
			msgicon = "icon_info";
			for i, win in ipairs(window.abilities.getWindows()) do
				statmsg = statmsg .. win.label.getValue() .. "         ";
				local node = win.getDatabaseNode();
				if DB.getChild(node, "temp") then
					DB.setValue(node, "temp", "number", win.temp.getValue());
					statmsg = statmsg .. win.temp.getValue() .. "/"; 
				end
				if DB.getChild(node, "potential") then
					DB.setValue(node, "potential", "number", win.pot.getValue());
					statmsg = statmsg .. win.pot.getValue() .. "\r";
				end
				win.temproll.setValue(0);
				win.potroll.setValue(0);
				win.extraroll.setValue(0);
				win.refresh();
			end
			window.resetNumRolls();
		end
	end
	local msg = {font = "msgfont", icon = msgicon, mode = "system"};
	msg.text = statmsg;
	Comm.deliverChatMessage(msg);
end

function onButtonPress()
	for i, win in ipairs(window.abilities.getWindows()) do
		if string.lower(OptionsManager.getOption("CL07")) == string.lower(Interface.getString("option_val_threecolumn")) then
			win.diceholderTemp.action();
			win.diceholderExtra.action();
		else
			win.diceholderTemp.action();
		end
		win.diceholderPot.action();
	end
end

