windowlist.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						--[[ load the stat list ]]
						local statList = Rules_Stats.List();
						for i = 1, #statList do
							addEntry(statList[i].name, statList[i].label, statList[i].devStat, statList[i].order);
						end
						--[[ force a re-sort ]]
						applySort();
					end

					function addEntry(name, label, dev, order)
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.label.setValue(label);
							win.order.setValue(order);
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end

					function setDPs()
						local total = 0; 
						
						if string.lower(OptionsManager.getOption("CL112")) == string.lower(Interface.getString("option_val_off")) then
							for i, win in ipairs(getWindows()) do
								if win.dev.getValue() == 1 then
									total = total + win.dp.getValue();
								end
							end
						else
							total = tonumber(OptionsManager.getOption("CL112"));
						end
						window.dptotal.setValue(total);
					end

