buttoncontrol.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						OptionsManager.registerCallback("CL07", refresh);
						refresh();
					end

					function onClose()
						OptionsManager.unregisterCallback("CL07", refresh);
					end

					function refresh()
						if string.lower(OptionsManager.getOption("CL07")) == string.lower(Interface.getString("option_val_randomfixed")) then
							setVisible(false);
						else
							setVisible(true);
						end
					end

					function onButtonPress()
						local swap = window.order.getValue() + 1;
						if swap == 11 then
							swap = 1;
						end
						for i,w in ipairs(window.windowlist.getWindows()) do
							if w.order.getValue() == swap then
								local temp = w.temproll.getValue();
								w.temproll.setValue(window.temproll.getValue());
								window.temproll.setValue(temp);
								temp = w.potroll.getValue();
								w.potroll.setValue(window.potroll.getValue());
								window.potroll.setValue(temp);
								temp = w.extraroll.getValue();
								w.extraroll.setValue(window.extraroll.getValue());
								window.extraroll.setValue(temp);
							end
						end
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						OptionsManager.registerCallback("CL07", refresh);
						refresh();
					end

					function onClose()
						OptionsManager.unregisterCallback("CL07", refresh);
					end

					function refresh()
						if string.lower(OptionsManager.getOption("CL07")) == string.lower(Interface.getString("option_val_randomfixed")) then
							setVisible(false);
						else
							setVisible(true);
						end
					end

					function onButtonPress()
						local swap = window.order.getValue() - 1;
						if swap == 0 then
							swap = 10;
						end
						for i,w in ipairs(window.windowlist.getWindows()) do
							if w.order.getValue() == swap then
								local temp = w.temproll.getValue();
								w.temproll.setValue(window.temproll.getValue());
								window.temproll.setValue(temp);
								temp = w.potroll.getValue();
								w.potroll.setValue(window.potroll.getValue());
								window.potroll.setValue(temp);
								temp = w.extraroll.getValue();
								w.extraroll.setValue(window.extraroll.getValue());
								window.extraroll.setValue(temp);
							end
						end
					end

