dice_ghost.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						OptionsManager.registerCallback("CL07", refresh);
						refresh();
					end

					function onClose()
						OptionsManager.unregisterCallback("CL07", refresh);
					end

					function refresh()
						if string.lower(OptionsManager.getOption("CL07")) ~= string.lower(Interface.getString("option_val_threecolumn")) then
							setVisible(false);
						else
							setVisible(true);
						end
					end

					function action(draginfo)
						local charNode = DB.getChild(window.getDatabaseNode(), "...");
						local rActor = ActorManager.resolveActor(charNode);
						ActionStatGen.performRoll(draginfo, rActor, ActionRMDice.D100, window.label.getValue(), "extraroll");

						return true;
					end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end

					function action(draginfo)
